func (this *CoinmetroCore) ParseTrade(trade any, optionalArgs ...any) any {
	//
	// fetchTrades
	//     {
	//         "pair": "ETHUSDT",
	//         "price": 2077.1513,
	//         "qty": 0.00337,
	//         "timestamp": 1700684816853,
	//         "seqNum": 10644567113
	//     },
	//
	// fetchMyTrades
	//     {
	//         "pair": "ETHUSDC",
	//         "seqNumber": 10873722343,
	//         "timestamp": 1702570610747,
	//         "qty": 0.002,
	//         "price": 2282,
	//         "side": "buy",
	//         "orderID": "65671262d93d9525ac009e36170257061073952c6423a8c5b4d6c"
	//     }
	//
	// fetchOrders
	//     {
	//         "_id": "657b31d360a9542449381bdc",
	//         "seqNumber": 10873722343,
	//         "timestamp": 1702570610747,
	//         "qty": 0.002,
	//         "price": 2282,
	//         "side": "buy"
	//     }
	//
	//    {
	//        "pair":"ETHUSDC",
	//        "seqNumber":"10873722343",
	//        "timestamp":"1702570610747",
	//        "qty":"0.002",
	//        "price":"2282",
	//        "side":"buy",
	//        "orderID":"65671262d93d9525ac009e36170257061073952c6423a8c5b4d6c",
	//        "userID":"65671262d93d9525ac009e36"
	//     }
	//
	market := GetArg(optionalArgs, 0, nil)
	_ = market
	var marketId any = this.SafeString2(trade, "symbol", "pair")
	market = this.SafeMarket(marketId, market)
	var symbol any = GetValue(market, "symbol")
	var id any = this.SafeStringN(trade, []any{"_id", "seqNum", "seqNumber"})
	var timestamp any = this.SafeInteger(trade, "timestamp")
	var priceString any = this.SafeString(trade, "price")
	var amountString any = this.SafeString(trade, "qty")
	var order any = this.SafeString(trade, "orderID")
	var side any = this.SafeString(trade, "side")
	return this.SafeTrade(map[string]any{
		"id":           id,
		"order":        order,
		"timestamp":    timestamp,
		"datetime":     this.Iso8601(timestamp),
		"symbol":       symbol,
		"type":         nil,
		"side":         side,
		"takerOrMaker": nil,
		"price":        priceString,
		"amount":       amountString,
		"cost":         nil,
		"fee":          nil,
		"info":         trade,
	}, market)
}

