func (this *CoinmetroCore) ParseTicker(ticker any, optionalArgs ...any) any {
	//
	//     {
	//         "pair": "PERPUSD",
	//         "timestamp": 1702549841973,
	//         "price": 0.8615317721366659,
	//         "qty": 1e-12,
	//         "ask": 0.8742333599999257,
	//         "bid": 0.8490376365388491
	//         "delta": 0.26915154078134096,
	//         "h": 0.86220315458898,
	//         "l": 0.67866757035154,
	//         "v": 2.835000000000001e-9,
	//         "sentimentData": {
	//             "sentiment": 36.71333333333333,
	//             "interest": 0.47430830039525695
	//         }
	//     }
	//
	market := GetArg(optionalArgs, 0, nil)
	_ = market
	var marketId any = this.SafeString(ticker, "pair")
	market = this.SafeMarket(marketId, market)
	var timestamp any = this.SafeInteger(ticker, "timestamp")
	var bid any = this.SafeString(ticker, "bid")
	var ask any = this.SafeString(ticker, "ask")
	var high any = this.SafeString(ticker, "h")
	var low any = this.SafeString(ticker, "l")
	var last any = this.SafeString(ticker, "price")
	var baseVolume any = this.SafeString(ticker, "v")
	var delta any = this.SafeString(ticker, "delta")
	var percentage any = Precise.StringMul(delta, "100")
	return this.SafeTicker(map[string]any{
		"symbol":        GetValue(market, "symbol"),
		"timestamp":     timestamp,
		"datetime":      this.Iso8601(timestamp),
		"open":          nil,
		"high":          high,
		"low":           low,
		"close":         nil,
		"last":          last,
		"bid":           bid,
		"bidVolume":     nil,
		"ask":           ask,
		"askVolume":     nil,
		"vwap":          nil,
		"previousClose": nil,
		"change":        nil,
		"percentage":    percentage,
		"average":       nil,
		"baseVolume":    baseVolume,
		"quoteVolume":   nil,
		"info":          ticker,
	}, market)
}

